#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#define MAXN 100005
#define MAXQ 100
int N, Q;
int edges[MAXN][3];
int queries[MAXQ][2];
int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}
int dfs(int node, int parent, int g) {
    int count = 0;
    for (int i = 0; i < N - 1; i++) {
        if (edges[i][0] == node || edges[i][1] == node) {
            int child = (edges[i][0] == node) ? edges[i][1] : edges[i][0];
            if (child != parent) {
                int new_g = gcd(g, edges[i][2]);
                count += dfs(child, node, new_g);
            }
        }
    }
    if (g == 1) count++;
    return count;
}
int main() {
    scanf("%d", &N);
    for (int i = 0; i < N - 1; i++) {
        scanf("%d %d %d", &edges[i][0], &edges[i][1], &edges[i][2]);
    }
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        scanf("%d %d", &queries[i][0], &queries[i][1]);
    }
    int count = dfs(1, -1, 1);
    printf("%d\n", count);
    for (int i = 0; i < Q; i++) {
        edges[queries[i][0] - 1][2] = queries[i][1];
        count = dfs(1, -1, 1);
        printf("%d\n", count);
    }
    return 0;
}

