import java.util.Scanner;
public class Main {
    static final int MAXN = 100005;
    static final int MAXQ = 100;
    static int N, Q;
    static int[][] edges;
    static int[][] queries;
    public static int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
    public static int dfs(int node, int parent, int g, int[][] edges) {
        int count = 0;
        for (int i = 0; i < edges.length; i++) {
            if (edges[i][0] == node || edges[i][1] == node) {
                int child = (edges[i][0] == node) ? edges[i][1] : edges[i][0];
                if (child != parent) {
                    int new_g = gcd(g, edges[i][2]);
                    count += dfs(child, node, new_g, edges);
                }
            }
        }
        if (g == 1) count++;
        return count;
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        N = scanner.nextInt();
        edges = new int[N - 1][3];
        for (int i = 0; i < N - 1; i++) {
            edges[i][0] = scanner.nextInt();
            edges[i][1] = scanner.nextInt();
            edges[i][2] = scanner.nextInt();
        }
        Q = scanner.nextInt();
        queries = new int[Q][2];
        for (int i = 0; i < Q; i++) {
            queries[i][0] = scanner.nextInt();
            queries[i][1] = scanner.nextInt();
        }
        int count = dfs(1, -1, 1, edges);
        System.out.println(count);
        for (int i = 0; i < Q; i++) {
            edges[queries[i][0] - 1][2] = queries[i][1];
            count = dfs(1, -1, 1, edges);
            System.out.println(count);
        }
    }
}

